/* ScrollTrigger stub — replace with real ScrollTrigger.min.js from https://cdnjs.cloudflare.com/ajax/libs/gsap/3.12.5/ScrollTrigger.min.js */
(function(){
  "use strict";
  var ST={
    create:function(v){
      var trig=typeof v.trigger==="string"?document.querySelector(v.trigger):(v.trigger||null);
      if(!trig)return{kill:function(){}};
      var fired=false;
      var io=new IntersectionObserver(function(entries){
        entries.forEach(function(e){
          if(e.isIntersecting&&!fired){
            fired=true;
            if(v.onEnter)v.onEnter();
            if(v.animation&&v.animation.play)v.animation.play();
            io.unobserve(trig);
          }
        });
      },{threshold:0.05});
      io.observe(trig);
      return{kill:function(){io.disconnect();}};
    },
    refresh:function(){},
    getAll:function(){return[];},
    kill:function(){},
    batch:function(targets,v){
      var els=typeof targets==="string"?Array.from(document.querySelectorAll(targets)):(Array.isArray(targets)?targets:[targets]);
      var io=new IntersectionObserver(function(entries){
        var batch=[];
        entries.forEach(function(e){if(e.isIntersecting)batch.push(e.target);});
        if(batch.length&&v.onEnter)v.onEnter(batch);
        batch.forEach(function(el){io.unobserve(el);});
      },{threshold:0.05});
      els.forEach(function(el){io.observe(el);});
    },
    addEventListener:function(){},
    removeEventListener:function(){},
    defaults:function(){},
    config:function(){}
  };
  window.ScrollTrigger=ST;
  if(window.gsap)window.gsap.registerPlugin=function(){};
})();
